proof fn phi_1_execution_equality_collapses_distinct_fns(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality(ex1, ex2);
}

proof fn phi_2_temp_pred_equality_forces_pred_equality(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p.pred == q.pred,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_3_suffix_zero_equals_self(ex: Execution<int>)
    ensures
        ex.suffix(0) == ex,
{
    execution_equality(ex.suffix(0), ex);
}

proof fn phi_4_suffix_composition_equals_addition(ex: Execution<int>, i: nat, j: nat)
    ensures
        ex.suffix(i).suffix(j) == ex.suffix(i + j),
{
    execution_equality(ex.suffix(i).suffix(j), ex.suffix(i + j));
}

proof fn phi_5_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p != q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}
